if (!msg.payload) {
    node.warn("payload undefined en Logica");
    return null;
}

let temperatura = msg.payload.temperatura;
let humedadSuelo = msg.payload.humedad_suelo;
let timestamp = msg.payload.timestamp;
let lecturaId = msg.lectura_id;
let nodeId = msg.payload.node_id;

// Validar datos
if (temperatura === undefined || humedadSuelo === undefined || !nodeId) {
    node.warn("faltan temperatura, humedad_suelo o node_id en Logica");
    return null;
}

let sueloSeco = humedadSuelo > 3000;
let sueloNormal = humedadSuelo <= 2500;
let temperaturaAlta = temperatura > 40;
let riegoNecesario = sueloSeco && temperaturaAlta;

let msgSueloSeco = null;
let msgTempAlta = null;
let msgRiego = null;
let msgSueloNormal = null;
let mensajeBomba = null;

if (sueloSeco) {
    msgSueloSeco = {
        payload: {
            lectura_id: lecturaId,
            node_id: nodeId,
            tipo_alerta: "suelo_seco",
            timestamp_alerta: timestamp
        }
    };
}

if (temperaturaAlta) {
    msgTempAlta = {
        payload: {
            lectura_id: lecturaId,
            node_id: nodeId,
            tipo_alerta: "temperatura_alta",
            timestamp_alerta: timestamp
        }
    };
}

if (riegoNecesario) {
    msgRiego = {
        payload: {
            lectura_id: lecturaId,
            node_id: nodeId,
            tipo_alerta: "necesidad_riego",
            timestamp_alerta: timestamp
        }
    };
}

if (sueloNormal) {
    msgSueloNormal = {
        payload: {
            lectura_id: lecturaId,
            node_id: nodeId,
            tipo_alerta: "suelo_normal",
            timestamp_alerta: timestamp
        }
    };
}

// Seleccion dinamica del topico de actuacion
let topicActuacion = null;

// El ESP32 real activa la bomba fisica
if (nodeId === "ESP32_1") {
    topicActuacion = "Parcial2_Bomba";
}

// SIM_1 tambien activa la bomba fisica, si asi lo necesitas para pruebas
if (nodeId === "SIM_1") {
    topicActuacion = "Parcial2_Bomba";
}

// El simulador Python NO activa la bomba fisica.
// Este activa solamente la pagina web.
if (nodeId === "PYTHON_VIRTUAL_1") {
    topicActuacion = "Parcial2_Pagina";
}

if (topicActuacion) {
    mensajeBomba = {
        topic: topicActuacion,
        payload: riegoNecesario ? "ON" : "OFF",
        lectura_id: lecturaId,
        node_id: nodeId,
        timestamp_alerta: timestamp,
        humedad_suelo: humedadSuelo
    };
} else {
    node.warn("node_id sin topico de actuacion configurado: " + nodeId);
}

return [msgSueloSeco, msgTempAlta, msgRiego, msgSueloNormal, mensajeBomba];

