// ===============================
// FUNCIONES AUXILIARES
// ===============================

function limpiarNumero(valor) {
    if (valor === null || valor === undefined || valor === "") {
        return null;
    }

    let n = Number(valor);

    if (isNaN(n)) {
        return null;
    }

    return n;
}

function promedio(arr) {
    if (arr.length === 0) return null;
    return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function mediana(arr) {
    if (arr.length === 0) return null;

    let datos = [...arr].sort((a, b) => a - b);
    let mitad = Math.floor(datos.length / 2);

    if (datos.length % 2 === 0) {
        return (datos[mitad - 1] + datos[mitad]) / 2;
    }

    return datos[mitad];
}

function moda(arr) {
    if (arr.length === 0) return null;

    let frecuencias = {};
    let maxFrecuencia = 0;
    let modaValor = arr[0];

    for (let valor of arr) {
        let clave = String(valor);
        frecuencias[clave] = (frecuencias[clave] || 0) + 1;

        if (frecuencias[clave] > maxFrecuencia) {
            maxFrecuencia = frecuencias[clave];
            modaValor = valor;
        }
    }

    return modaValor;
}

function minimo(arr) {
    if (arr.length === 0) return null;
    return Math.min(...arr);
}

function maximo(arr) {
    if (arr.length === 0) return null;
    return Math.max(...arr);
}

function varianza(arr) {
    if (arr.length === 0) return null;

    let media = promedio(arr);
    let suma = arr.reduce((acc, valor) => {
        return acc + Math.pow(valor - media, 2);
    }, 0);

    return suma / arr.length;
}

function desviacionEstandar(arr) {
    let v = varianza(arr);
    if (v === null) return null;
    return Math.sqrt(v);
}

function calcularMetricas(arr) {
    let min = minimo(arr);
    let max = maximo(arr);

    return {
        media: promedio(arr),
        mediana: mediana(arr),
        moda: moda(arr),
        minima: min,
        maxima: max,
        rango: min !== null && max !== null ? max - min : null,
        desviacion: desviacionEstandar(arr),
        varianza: varianza(arr)
    };
}

function sqlNumber(valor) {
    if (valor === null || valor === undefined || isNaN(valor)) {
        return "NULL";
    }

    return Number(valor).toFixed(4);
}

function sqlString(valor) {
    if (valor === null || valor === undefined) {
        return "";
    }

    return String(valor).replace(/'/g, "''");
}

function formatearFechaMySQL(valor) {
    if (!valor) {
        return null;
    }

    // Si MySQL ya manda formato string tipo "2026-05-27 18:00:00"
    if (typeof valor === "string") {
        return valor.replace("T", " ").slice(0, 19);
    }

    // Si MySQL manda objeto Date
    let fecha = new Date(valor);

    if (isNaN(fecha.getTime())) {
        return null;
    }

    return fecha.toISOString().slice(0, 19).replace("T", " ");
}

// ===============================
