    }

    grupos[nodeId].push(fila);
}

// ===============================
// CALCULAR METRICAS
// ===============================

let inserts = [];

for (let nodeId in grupos) {
    let datos = grupos[nodeId];

    let temperaturas = datos
        .map(f => limpiarNumero(f.temperatura))
        .filter(v => v !== null);

    let humedadesAire = datos
        .map(f => limpiarNumero(f.humedad_aire))
        .filter(v => v !== null);

    let humedadesSuelo = datos
        .map(f => limpiarNumero(f.humedad_suelo))
        .filter(v => v !== null);

    if (
        temperaturas.length === 0 &&
        humedadesAire.length === 0 &&
        humedadesSuelo.length === 0
    ) {
        continue;
    }

    let metTemp = calcularMetricas(temperaturas);
    let metHumAire = calcularMetricas(humedadesAire);
    let metHumSuelo = calcularMetricas(humedadesSuelo);

    let idsValidos = datos
        .map(f => Number(f.lectura_bruta_id))
        .filter(v => !isNaN(v));

    if (idsValidos.length === 0) {
        node.warn("No hay lectura_bruta_id valido para node_id: " + nodeId);
        continue;
    }

    let lecturaBrutaId = Math.max(...idsValidos);

    let fechasValidas = datos
        .map(f => formatearFechaMySQL(f.timestamp_sensor))
        .filter(f => f !== null);

    if (fechasValidas.length === 0) {
        node.warn("No hay fechas validas para node_id: " + nodeId);
        continue;
    }

    fechasValidas.sort();

    let fechaInicio = fechasValidas[0];
    let fechaFin = fechasValidas[fechasValidas.length - 1];

    let totalRegistros = datos.length;

    let cantidadIncidencias = datos.filter(f => {
        return f.incidencia_id !== null && f.incidencia_id !== undefined;
    }).length;

    let cantidadDuplicados = datos.filter(f => {
        return f.tipo_incidencia &&
            String(f.tipo_incidencia).includes("duplicado");
    }).length;

    let cantidadImputados = datos.filter(f => {
        return f.metodo_aplicado &&
            (
                String(f.metodo_aplicado).includes("media_movil") ||
                String(f.metodo_aplicado).includes("valor_por_defecto") ||
                String(f.metodo_aplicado).includes("validacion_rango")
            );
    }).length;

    let cantidadAnomalias = datos.filter(f => {
        return f.tipo_incidencia &&
            (
                String(f.tipo_incidencia).includes("fuera_rango") ||
                String(f.tipo_incidencia).includes("valor_fuera_rango")
            );
    }).length;

    inserts.push(`(
        ${lecturaBrutaId},
        '${sqlString(nodeId)}',

        '${fechaInicio}',
        '${fechaFin}',
        ${totalRegistros},

        ${sqlNumber(metTemp.media)},
        ${sqlNumber(metTemp.mediana)},
        ${sqlNumber(metTemp.moda)},
        ${sqlNumber(metTemp.minima)},
        ${sqlNumber(metTemp.maxima)},
        ${sqlNumber(metTemp.rango)},
        ${sqlNumber(metTemp.desviacion)},
        ${sqlNumber(metTemp.varianza)},

        ${sqlNumber(metHumAire.media)},
        ${sqlNumber(metHumAire.mediana)},
        ${sqlNumber(metHumAire.moda)},
        ${sqlNumber(metHumAire.minima)},
        ${sqlNumber(metHumAire.maxima)},
        ${sqlNumber(metHumAire.rango)},
        ${sqlNumber(metHumAire.desviacion)},
        ${sqlNumber(metHumAire.varianza)},

        ${sqlNumber(metHumSuelo.media)},
        ${sqlNumber(metHumSuelo.mediana)},
        ${sqlNumber(metHumSuelo.moda)},
        ${sqlNumber(metHumSuelo.minima)},
        ${sqlNumber(metHumSuelo.maxima)},
        ${sqlNumber(metHumSuelo.rango)},
        ${sqlNumber(metHumSuelo.desviacion)},
        ${sqlNumber(metHumSuelo.varianza)},

        ${cantidadIncidencias},
        ${cantidadDuplicados},
        ${cantidadImputados},
        ${cantidadAnomalias}
    )`);
}

