function sqlString(value) {
    if (value === undefined || value === null) {
        return "";
    }
    return String(value).replace(/'/g, "''");
}

function sqlNullable(value) {
    if (value === undefined || value === null || value === "") {
        return "NULL";
    }
    return `'${sqlString(value)}'`;
}

